import{_ as e,o as a,c as o,a2 as l}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"复利 Compounding","description":"巴菲特99%的财富是在50岁之后获得的，复利是世界中第八大奇迹","frontmatter":{"title":"复利 Compounding","description":"巴菲特99%的财富是在50岁之后获得的，复利是世界中第八大奇迹"},"headers":[],"relativePath":"02_concepts/compounding.md","filePath":"02_concepts/compounding.md"}'),r={name:"02_concepts/compounding.md"};function h(d,t,p,n,i,s){return a(),o("div",null,[...t[0]||(t[0]=[l('<h1 id="复利-compounding" tabindex="-1">复利 Compounding <a class="header-anchor" href="#复利-compounding" aria-label="Permalink to &quot;复利 Compounding&quot;">​</a></h1><blockquote><p>&quot;复利是世界第八大奇迹。理解它的人赚取它，不理解的人支付它。&quot; —— <a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>（引用爱因斯坦语）</p></blockquote><p>复利是<a href="/04_people/沃伦·巴菲特.html">巴菲特</a>财富帝国最底层的秘密武器，也是他一生中反复向投资者传递的核心信息。理解复利，你就能理解为什么<a href="/04_people/沃伦·巴菲特.html">巴菲特</a>说&quot;慢慢变富&quot;是世界上最被低估的策略。</p><hr><h2 id="核心出处" tabindex="-1">核心出处 <a class="header-anchor" href="#核心出处" aria-label="Permalink to &quot;核心出处&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">年份</th><th style="text-align:left;">重点内容</th></tr></thead><tbody><tr><td style="text-align:left;">**[[/01_letters/1965年/核心总结</td><td style="text-align:left;">1965年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/1993年/核心总结</td><td style="text-align:left;">1993年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2003年/核心总结</td><td style="text-align:left;">2003年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2013年/核心总结</td><td style="text-align:left;">2013年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2023年/核心总结</td><td style="text-align:left;">2023年]]**</td></tr></tbody></table><hr><h2 id="一、什么是复利" tabindex="-1">一、什么是复利 <a class="header-anchor" href="#一、什么是复利" aria-label="Permalink to &quot;一、什么是复利&quot;">​</a></h2><p>复利的本质是<strong>利滚利</strong>——不仅本金产生利息，利息再产生利息，周而复始，雪球越滚越大。</p><p>用一个简单公式表达：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>最终财富 = 本金 × (1 + 年化收益率)^年数</span></span></code></pre></div><p>但这个公式背后的含义远比数字本身惊人。</p><p><strong>一张纸对折50次，厚度能到达月球吗？</strong></p><p>答案是：可以。2^50 = 1.12 × 10^15，对折50次的纸张厚度约为1.13亿公里，超过地球到月球的距离（38万公里）。</p><p>这就是复利的威力——<strong>指数级增长</strong>。</p><hr><h2 id="二、巴菲特的复利奇迹" tabindex="-1">二、<a href="/04_people/沃伦·巴菲特.html">巴菲特</a>的复利奇迹 <a class="header-anchor" href="#二、巴菲特的复利奇迹" aria-label="Permalink to &quot;二、[[巴菲特]]的复利奇迹&quot;">​</a></h2><h3 id="惊人的时间账本" tabindex="-1">惊人的时间账本 <a class="header-anchor" href="#惊人的时间账本" aria-label="Permalink to &quot;惊人的时间账本&quot;">​</a></h3><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>的财富轨迹，是一张复利最好的注解：</p><table tabindex="0"><thead><tr><th>年龄</th><th>财富规模</th><th>说明</th></tr></thead><tbody><tr><td>30岁</td><td>约100万美元</td><td>人生第一个百万</td></tr><tr><td>39岁</td><td>约2500万美元</td><td>布法罗晚报收购案时期</td></tr><tr><td>53岁</td><td>约10亿美元</td><td>1990年突破10亿</td></tr><tr><td>72岁</td><td>约360亿美元</td><td>2006年进入全球前五</td></tr><tr><td>89岁</td><td>约800亿美元</td><td>2019年数据</td></tr><tr><td>94岁（2025）</td><td>约1600亿美元</td><td>全球第二大富豪</td></tr></tbody></table><blockquote><p>&quot;我从6岁开始储蓄。复利教会我：财富的积累靠的是时间，而不是速度。&quot;——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a></p></blockquote><h3 id="_99-的财富来自50岁之后" tabindex="-1">99%的财富来自50岁之后 <a class="header-anchor" href="#_99-的财富来自50岁之后" aria-label="Permalink to &quot;99%的财富来自50岁之后&quot;">​</a></h3><p>这是理解<a href="/04_people/沃伦·巴菲特.html">巴菲特</a>最震撼的数字之一：</p><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>在52岁时净资产约7亿美元；到90岁时超过1000亿美元。这意味着他<strong>超过98%的财富是在50岁之后积累的</strong>。</p><p>不是50岁之后他变得更聪明了，而是<strong>时间终于站在了他这一边</strong>——复利在指数曲线的后半段，展现出了惊人的加速度。</p><blockquote><p>&quot;复利最美好的地方在于，它不需要你更聪明，只需要你更耐心。&quot;——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a></p></blockquote><hr><h2 id="三、复利的两大敌人" tabindex="-1">三、复利的两大敌人 <a class="header-anchor" href="#三、复利的两大敌人" aria-label="Permalink to &quot;三、复利的两大敌人&quot;">​</a></h2><h3 id="敌人一-摩擦成本" tabindex="-1">敌人一：摩擦成本 <a class="header-anchor" href="#敌人一-摩擦成本" aria-label="Permalink to &quot;敌人一：摩擦成本&quot;">​</a></h3><p>每一次交易、每一笔费用、每一分税费，都是复利的&quot;漏电口&quot;。</p><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>的老师<a href="/04_people/本·格雷厄姆.html">格雷厄姆</a>曾说过：</p><blockquote><p>&quot;投资的成功，5%取决于聪明的脑袋，95%取决于你能否控制住自己不去频繁折腾。&quot;</p></blockquote><p>为什么大多数主动基金跑不赢指数？因为交易佣金、管理费、税费不断蚕食收益，每年看似不起眼的2%费用，在30年后可能吞噬你50%以上的财富。</p><blockquote><p>&quot;在投资领域，没有什么比习惯性摩擦成本更危险的了。市场的短期波动对长期复利几乎没有影响，但费用和税是持续的、确定的损耗。&quot;——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，1993年致股东信</p></blockquote><h3 id="敌人二-中断" tabindex="-1">敌人二：中断 <a class="header-anchor" href="#敌人二-中断" aria-label="Permalink to &quot;敌人二：中断&quot;">​</a></h3><p>复利的核心是<strong>不中断</strong>。</p><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>的搭档<a href="/04_people/查理·芒格.html">查理·芒格</a>曾说过：</p><blockquote><p>&quot;复利最关键的因素有两个：第一，稳健的年化收益率；第二，永远不打断它。&quot;</p></blockquote><p>一次重大亏损，一次错误的时机退出，都可能让多年积累付之东流。保住本金，永远是复利的第一要务。</p><blockquote><p>&quot;投资的第一原则是：永远不要亏损。第二原则是：永远不要忘记第一条。&quot;——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a></p></blockquote><hr><h2 id="四、巴菲特如何最大化复利" tabindex="-1">四、<a href="/04_people/沃伦·巴菲特.html">巴菲特</a>如何最大化复利 <a class="header-anchor" href="#四、巴菲特如何最大化复利" aria-label="Permalink to &quot;四、[[巴菲特]]如何最大化复利&quot;">​</a></h2><h3 id="_1-长期持有-不折腾" tabindex="-1">1. 长期持有，不折腾 <a class="header-anchor" href="#_1-长期持有-不折腾" aria-label="Permalink to &quot;1. 长期持有，不折腾&quot;">​</a></h3><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>持有<a href="/03_companies/可口可乐.html">可口可乐</a>超过35年，持有<a href="/03_companies/美国运通.html">美国运通</a>超过30年。持有<a href="/03_companies/吉列.html">吉列</a>/<a href="/03_companies/宝洁.html">宝洁</a>超过20年。</p><blockquote><p>&quot;如果你不愿意持有一只股票十年，那就不要考虑持有它十分钟。&quot;——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a></p></blockquote><p>这句话的底层逻辑，正是复利：每一次卖出都有成本，每一次买入都有等待期。频繁换手不仅浪费了复利的时间，还增加了犯错的机会。</p><h3 id="_2-只投真正优秀的企业" tabindex="-1">2. 只投真正优秀的企业 <a class="header-anchor" href="#_2-只投真正优秀的企业" aria-label="Permalink to &quot;2. 只投真正优秀的企业&quot;">​</a></h3><p>复利的前提是<strong>持续的正向收益</strong>。</p><p>平庸企业的利润可能逐年波动甚至亏损，复利曲线起起落落；优秀企业的利润持续增长，复利曲线陡峭向上。</p><blockquote><p>&quot;复利像从山上滚下来的雪球。只要雪潮湿、松软，雪球够大，山坡够长，你就能滚出一个巨大的雪球。&quot;——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a></p></blockquote><h3 id="_3-不分红再投资" tabindex="-1">3. 不分红再投资 <a class="header-anchor" href="#_3-不分红再投资" aria-label="Permalink to &quot;3. 不分红再投资&quot;">​</a></h3><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>长期坚持不分红，将<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>所有利润再投入。他说：</p><blockquote><p>&quot;每保留一美元利润，如果能创造超过一美元的市值，就是值得的。<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>的每一块钱留存收益，在我的管理下会创造超过一块钱的价值。&quot;</p></blockquote><p>这就是复利的极致应用：<strong>将每一分收益转化为新的本金</strong>。</p><blockquote><p>&quot;<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>股价在1965年至2023年间，从18美元涨到了超过54万美元，年化收益率约19.8%。如果你在1965年投入1万美元持有到现在，价值约为4亿美元。&quot;——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，2023年致股东信</p></blockquote><hr><h2 id="五、复利的数学启示" tabindex="-1">五、复利的数学启示 <a class="header-anchor" href="#五、复利的数学启示" aria-label="Permalink to &quot;五、复利的数学启示&quot;">​</a></h2><h3 id="年化收益率的力量" tabindex="-1">年化收益率的力量 <a class="header-anchor" href="#年化收益率的力量" aria-label="Permalink to &quot;年化收益率的力量&quot;">​</a></h3><table tabindex="0"><thead><tr><th>年化收益率</th><th>10年</th><th>20年</th><th>30年</th><th>40年</th></tr></thead><tbody><tr><td>10%</td><td>2.6x</td><td>6.7x</td><td>17.4x</td><td>45.3x</td></tr><tr><td>15%</td><td>4.0x</td><td>16.4x</td><td>66.2x</td><td>267x</td></tr><tr><td>20%</td><td>6.2x</td><td>38.3x</td><td>237x</td><td>1469x</td></tr><tr><td>25%</td><td>9.3x</td><td>86.7x</td><td>808x</td><td>7524x</td></tr></tbody></table><p>同样的本金、同样的时间，不同的年化收益率，最终结果相差可能高达百倍。<strong>收益率的微小差异，在时间的作用下会变成天壤之别</strong>。</p><h3 id="晚起步10年的代价" tabindex="-1">晚起步10年的代价 <a class="header-anchor" href="#晚起步10年的代价" aria-label="Permalink to &quot;晚起步10年的代价&quot;">​</a></h3><p>25岁投入1万元，年化20%，到65岁 = 910万元<br> 35岁投入1万元，年化20%，到65岁 = 186万元</p><p>晚10年起步，最终财富相差近5倍。<strong>复利最大的代价，是时间的浪费</strong>。</p><hr><h2 id="六、复利与安全边际" tabindex="-1">六、复利与安全边际 <a class="header-anchor" href="#六、复利与安全边际" aria-label="Permalink to &quot;六、复利与安全边际&quot;">​</a></h2><p>复利和安全边际是<a href="/04_people/沃伦·巴菲特.html">巴菲特</a>投资哲学中不可分割的一对概念：</p><ul><li><strong>安全边际</strong>决定了你的买入质量（本金不亏损）</li><li><strong>复利</strong>决定了你的财富增长速度（时间发挥作用）</li></ul><p>没有安全边际的复利，是在沙漏上建城堡；没有复利的安全边际，是手握现金却让通胀蚕食购买力。</p><blockquote><p>&quot;投资的全部秘密在于：在本金安全的前提下，用合理的价格买入能持续产生现金流的资产，然后让时间为你工作。&quot;——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a></p></blockquote><hr><h2 id="相关主题" tabindex="-1">相关主题 <a class="header-anchor" href="#相关主题" aria-label="Permalink to &quot;相关主题&quot;">​</a></h2><ul><li><a href="./safety-margin.html">安全边际</a> — 复利得以持续的基础：永远保护好你的本金</li><li><a href="./../02_value/intrinsic-value.html">内在价值</a> — 识别真正值得复利的好企业</li><li><a href="./../02_value/moat.html">护城河</a> — 护城河越宽，复利曲线越陡峭</li><li><a href="./../02_thinking/long-term-thinking.html">长期投资</a> — 复利需要时间，拒绝短期干扰</li></ul>',72)])])}const q=e(r,[["render",h]]);export{c as __pageData,q as default};
